var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"실험한 내용들을 아주 상세하게 기록해 놨어.","JPN":"実験の内容がとても詳しく記録されていたわ。","ENG":"Ludwig kept detailed records of his experiments.","TWN":"我已經詳細記錄了實驗內容。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"정리한 내용들만 간추려서 이야기해 줄게.","JPN":"まとめた内容をざっと話すわね。","ENG":"I'll summarize the key findings for you.","TWN":"我只會簡要地告訴你整理好的內容。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"루드윅은 감염자의 핏속에 들어 있는 인자가 붉은 달 현상을 유도한다는 사실을 깨달았어.","JPN":"ルードヴィヒは、感染者の血液に含まれているファクターが赤い月現象を誘導するという事実を発見した。","ENG":"He discovered that the factor within an afflicted's blood triggers the Red Moon phenomenon.","TWN":"路易發現感染者血液中的因子會引發紅月現象。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 가설을 증명하기 위해 멍멍이를 직접 실험대 위에 올리려고 한 거고.","JPN":"その仮説を証明するために、ワンちゃんで直接実験しようとした。","ENG":"And to prove his theory... he was planning to put you on the test table, Puppy.","TWN":"為了證明那個假設，他打算把狗狗直接放到實驗台上。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 그 한계는 명확했죠.","JPN":"でも、そこには明確な限界が存在しました。","ENG":"But his limits were obvious.","TWN":"但那終究是有限的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"결국 침식 쐐기의 역할을 하는 매개만 부수면 끝나는 일이었으니까요.","JPN":"結局、侵食楔の役割をする媒介さえ壊せば済む話でしたから。","ENG":"In the end, all it took was breaking the medium that acted as a Corrupted Wedge.","TWN":"畢竟只要破壞代替侵蝕釘作用的媒介就行了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"유의미한 결론을 낸 것도 사실이야.","JPN":"でも有意義な結論を出したのも事実よ。","ENG":"Still, his conclusions were meaningful.","TWN":"得出了有意義的結論也是事實。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이상 침식 현상을 일으킨 존재가 있다는 것을 알아냈으니까.","JPN":"異常侵食現象を起こした存在がいる、ということがわかったのだから。","ENG":"Through you, he confirmed that some entity triggered the Aberrant Counterside Effect.","TWN":"因為發現了引起異常侵蝕現象的存在。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"존재만으로도…… 영향을 주는…….","JPN":"存在だけで……影響を及ぼす……","ENG":"An entity that... influences just by existing...","TWN":"僅僅是存在……就能產生影響……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래.","JPN":"ええ。","ENG":"Exactly.","TWN":"好吧。"},"stage":{"bg":"MS_1203","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"세계에 넘어오는 것만으로도 영향을 미치는 존재들이지.","JPN":"この世界に現れるだけで、多大な影響を与える存在たち。","ENG":"There are beings that influence the world simply by crossing over.","TWN":"僅僅是來到這個世界就能產生影響的存在。"},"stage":{"bg":"MS_1203","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"로터스에 내렸던 눈이라던가…… 그런 것들 말이야.","JPN":"ロータスに降った雪とか……そういうものよ。","ENG":"Like the snowfall over Lotus... and other such anomalies.","TWN":"比如說洛德斯下的雪……之類的。"},"stage":{"bg":"MS_1203","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 이상 침식 현상도 그런 존재들에 의해 일어난 거예요?","JPN":"じゃあ、異常侵食現象もそういう存在によって起こったんですか？","ENG":"So the Aberrant Counterside Effect was caused by one of these beings?","TWN":"那麼異常侵蝕現象也是由那些存在引起的嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうね。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"추측에 불과하지만, 부력의 원리와 비슷할지도 모르지.","JPN":"これはあくまでも推測だけど、浮力に近い原理なのかもしれないわ。","ENG":"Think of it as a side effect.","TWN":"雖然只是猜測，但可能和浮力的原理相似。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"부력이요?","JPN":"浮力、ですか？","ENG":"Side effect...?","TWN":"浮力嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"물이 가득 찬 욕조에 들어가면 질량만큼의 물이 넘치는 것과 같은 원리야.","JPN":"お湯をいっぱい張った湯舟に入ると、質量分のお湯が溢れるのと同じ原理ね。","ENG":"It's like when you step into a full bathtub, and the water spills over.","TWN":"就像進入裝滿水的浴缸時，會溢出與品質相同的水一樣的原理。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"세계에 영향을 미치는 존재가 우리 세상에 들어온 만큼, 그만큼의 침식파가 흘러넘치게 되는 거지.","JPN":"世界に影響を与える存在がこっちの世界に入って来たってことは、その分侵食波が溢れるってことなの。","ENG":"When a being that affects reality enters this world, it displaces enough energy to unleash Corruption rays.","TWN":"對這個世界產生影響的存在進入我們的世界，侵蝕波就會跟著氾濫起來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"마왕이 일으켰다기엔 범위가 집약적이고, 일개 침식체가 일으켰다기엔 지나치게 광범위해.","JPN":"魔王の仕業とするには範囲が集約的すぎるし、ただの侵食体の仕業とするには範囲が広すぎる。","ENG":"If this were caused by a Demon Lord, the effect would be too localized. But it's far too widespread to be the work of a C.O.","TWN":"說是魔王引起的，範圍又太集中；說是某個侵蝕體引起的，又過於廣泛。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 뜻인지 알지?","JPN":"どういう意味か、わかるわよね？","ENG":"You understand what that means, right?","TWN":"知道什麼意思嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……사도.","JPN":"……使徒。","ENG":"...An Apostle.","TWN":"……使徒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사도가 이 세계에 강림했을 때의 반동이로군요.","JPN":"使徒がこの世界に降臨した時の反動ですね。","ENG":"It was caused by an Apostle descending into this world.","TWN":"這是使徒降臨這個世界時的反作用力。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시 멍멍이야. 돈을 벌려면 머리도 좋아야 한다는 걸 잘 보여주고 있어.","JPN":"さすがワンちゃん。お金儲けには頭の切れが必要ってことを存分に証明してるわね。","ENG":"That's right, Puppy. You show that making money requires brains, too.","TWN":"果然是狗狗。為了賺錢，頭腦也要聰明，這一點你表現得很好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"자~ 에그타르트 하나~","JPN":"はい、エッグタルト1個～","ENG":"Here, have an egg tart.","TWN":"來～賞你個個蛋撻～"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L41_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그러면 저나 카타리나는…….","JPN":"じゃあ、私やカタリナは……","ENG":"Then... does that mean Katharina and I–","TWN":"那樣的話，我和卡特莉娜……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠들어 있던 환상종의 인자가 발현한 거야.","JPN":"眠っていた幻想種のファクターが発現したの。","ENG":"The Bygone Factor that lay dormant was awakened.","TWN":"沉睡中的夢幻品種因子顯現出來了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"다만 이상 침식 현상으로 인한 변이였기에 부작용이 나타난 거고.","JPN":"ただ、異常侵食現象による変異だったせいで、副作用が出たわけね。","ENG":"But because it happened through an Aberrant Counterside Effect, there were side effects.","TWN":"只是因為是異常侵蝕現象引起的變異，所以才會出現副作用。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래서 광증을 일으키거나 혈액 외 섭식을 거부하는 등의 특징이 나타나는 거지.","JPN":"だから狂症が発症したり、血液以外のものの摂取を拒否したりする特徴が現れるの。","ENG":"That's why you suffer from madness, and why she refuses to consume anything but blood.","TWN":"所以才會出現引發狂症，或拒絕攝取血液以外的食物等特徵。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"언니는 이미 알고 있었던 건가요?","JPN":"姉さんは知ってたんですか？","ENG":"Did you already know all this?","TWN":"姊姊已經知道了嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이상 침식 현상을 일으켰을 줄은 몰랐어.","JPN":"異常侵食現象を起こしたとは思わなかったわ。","ENG":"I didn't realize it was caused by the Aberrant Counterside Effect.","TWN":"沒想到會引發異常侵蝕現象。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"내 윗사람들은 알고 있을지도 모르지만.","JPN":"上の人たちなら知ってたかもしれないね。","ENG":"But my superiors might have.","TWN":"我的上級可能知道。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사도들을 없앤다면, 이 병도 치료할 수 있을까요?","JPN":"使徒を排除したら、この病気も治るでしょうか？","ENG":"If we eliminate the Apostles, can this sickness be cured?","TWN":"如果消滅了使徒，這病也能治好嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무것도 확신할 수 없어.","JPN":"何も確信はできないわ。","ENG":"There are no guarantees.","TWN":"什麼都不能確定。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만…… 시도하지 않으면 알 수 없는 일도 있는 법이지.","JPN":"でも……やってみないとわからないこともこの世にはあるものね。","ENG":"But... there are things we won't know unless we try.","TWN":"但是……有些事情不嘗試是不會知道的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……언니 말이 맞아요.","JPN":"……そうですね。","ENG":"...You're right.","TWN":"……姊姊說的對。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"subtitle","speaker":null,"text":{"KOREA":"3 주일 뒤","JPN":"3週間後","ENG":"3 weeks later","TWN":"3週後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"이건…… 이단의 장식?","JPN":"これは……異端の飾り？","ENG":"This is... a heretic's emblem?","TWN":"這是…… 異端的裝飾？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"큰 소리로 말하지 마.","JPN":"大声で言わない。","ENG":"Keep your voice down.","TWN":"別大聲說話。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 동네에선 구원의 표식이란 말이야.","JPN":"この街では救済の印なの。","ENG":"Around here, it's a symbol of salvation.","TWN":"在這個地方，這就是救贖的標誌。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뒤에서 그냥 사람 좋은 미소만 짓고 있어.","JPN":"私の後ろでニコニコしてて。","ENG":"Just stand back and smile like a good little nun.","TWN":"在後面保持著和善的微笑就好。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"저…… 혹시 저희 마을로 오시기로 한 수녀님들이신가요?","JPN":"あの……もしかして、この街に来るというシスターの方々でしょうか？","ENG":"Um... are you the Sisters who were supposed to come to our village?","TWN":"那……你們是要來我們村莊的修女嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어머! 주님의 품을 찾는 어린 양께서 여기 계셨군요!","JPN":"まあ！　主の救いを求める子羊がここにいたのですね！","ENG":"Oh, my! A lost lamb in search of the Lord's embrace!","TWN":"哎呀！原來尋找主懷抱的小羊在這裡啊！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"악령이 깃든 곳은 어디인가요?","JPN":"悪霊が現れた場所はどこですか？","ENG":"Where is the place cursed by an evil spirit?","TWN":"惡靈附身之地在哪裡？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"왜 죽상이야.","JPN":"なんで渋い顔してるんだよ。","ENG":"What's with the long face?","TWN":"怎麼一副要死的樣子。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"일단 사도고 뭐고 먹고 살아야 단서를 찾을 거 아냐.","JPN":"使徒を倒すにしても、まず生活ができないと手がかりも探せないだろう。","ENG":"We need to eat before we can track down an Apostle.","TWN":"不管是使徒還是其他，得先吃飽了才能找線索啊。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고 우리 같은 사람들이 더 있을 수도 있어.","JPN":"それに、私たちみたいな人がまたいるかもしれない。","ENG":"Besides, there might be others like us out there.","TWN":"而且可能還有像我們這樣的人。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>사도를 사냥하기 위해선</color>, 그런 사람들을 모아야 한다고.","JPN":"<color=#ffd34c>使徒を狩るためには</color>、そういう人を集める必要があるの。","ENG":"<color=#ffd34c>To hunt an Apostle</color>, we need to gather people like us.","TWN":"<color=#ffd34c>為了獵殺使徒</color>，需要召集那樣的人。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"아뇨…… 불량식품은 오늘도 맛있는 냄새가 난다 싶어서…….","JPN":"違うんです……お菓子さん、今日も美味しそうな匂いがするなって……","ENG":"Oh... I was just thinking that you smell delicious as well today, Junk food...","TWN":"沒有……只是覺得今天的垃圾食物也散發著美味的香氣……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……초 치지 말고 저기 멀리 떨어져서 얌전히 있어.","JPN":"……余計なこと言ってないで、あっちで大人しく待ってて。","ENG":"...Ugh, stop ruining the mood and just go stand over there.","TWN":"……別搗亂，乖乖待遠點。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"아깐 뒤에만 붙어 있으라면서요.","JPN":"さっきは後ろにくっついてろって言ったくせに。","ENG":"But earlier, you told me to stay behind you.","TWN":"剛才還說讓我跟在你後面呢。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"불량식품의 옷 냄새만 맡아도 좋은데…….","JPN":"お菓子さんの服の匂いを嗅ぐだけでも十分なのに……","ENG":"Even just smelling your clothes makes me feel better...","TWN":"能聞到垃圾食物的味道就滿足了……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"얼른 마을로 가시죠! 악령의 냄새가 진동하네요!","JPN":"早く街へ行きましょう！　悪霊の匂いがぷんぷんします！","ENG":"Let's hurry to the village! The stench of an evil spirit is thick in the air!","TWN":"快去村裡吧！惡靈的氣息彌漫著呢！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_ESPR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_ESPR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 혹시 일을 해결하면 마을에서 하루 묵고 갈 수 있을까요?","JPN":"あ、事件が解決したら一晩泊まらせてもらってもよろしいでしょうか？","ENG":"By the way, if we purge this evil, would we be able to spend the night in the village?","TWN":"啊，如果解決了事情，可以在村子裡住一晚嗎？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고 이 주변에서 <color=#ffd34c>늑대</color>가 나타난다는 소문을 들어서요.","JPN":"あと、この辺で<color=#ffd34c>オオカミ</color>が現れるという噂を聞きまして……","ENG":"Oh, and I heard rumors about a wolf roaming these parts.","TWN":"而且我聽說這附近有<color=#ffd34c>狼</color>出沒。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그 일도 겸사겸사 처리해 드릴까요?","JPN":"ついでにその件も処理いたしましょうか？","ENG":"Should we take care of that while we're at it?","TWN":"那件事順便幫你處理掉吧？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"물론, 유료입니다.","JPN":"もちろん、お金はいただきますが。","ENG":"Of course, it's not free.","TWN":"當然是要收錢的囉。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};